    47→  --color-error: oklch(58% 0.253 17.585);
    48→  --color-error-content: oklch(96% 0.015 12.422);
    49→  --radius-selector: 0.25rem;
    50→  --radius-field: 0.25rem;
    51→  --radius-box: 0.5rem;
    52→  --size-selector: 0.21875rem;
    53→  --size-field: 0.21875rem;
    54→  --border: 1.5px;
    55→  --depth: 1;
    56→  --noise: 0;
    57→}
